@app.route("/documents", methods=["GET"])
def query_documents():
    title = request.args.get("title")
    status = request.args.get("status")
    tag = request.args.get("tag")
    user_id = request.args.get("user_id")
    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)

    query = {}
    if title:
        query["title"] = {"$regex": title, "$options": "i"}
    if status:
        query["status"] = status
    if tag:
        query["tags"] = tag
    if user_id:
        try:
            query["user_id"] = ObjectId(user_id)
        except Exception:
            return jsonify({"error": "Invalid user_id"}), 400

    cursor = documents_collection.find(query).sort("created_at", -1).skip(skip).limit(limit)
    results = [serialize_doc(doc) for doc in cursor]
    return jsonify({"count": len(results), "results": results}), 200


@app.route("/documents/search", methods=["POST"])
def advanced_document_search():
    data = request.get_json(force=True) or {}
    pipeline = []

    match_stage = {}
    if "status" in data:
        match_stage["status"] = data["status"]
    if "user_id" in data:
        try:
            match_stage["user_id"] = ObjectId(data["user_id"])
        except Exception:
            return jsonify({"error": "Invalid user_id"}), 400
    if "tags" in data and isinstance(data["tags"], list) and data["tags"]:
        match_stage["tags"] = {"$in": data["tags"]}
    if "text" in data:
        match_stage["$or"] = [
            {"title": {"$regex": data["text"], "$options": "i"}},
            {"content": {"$regex": data["text"], "$options": "i"}},
        ]

    if match_stage:
        pipeline.append({"$match": match_stage})

    pipeline.append(
        {
            "$lookup": {
                "from": "users",
                "localField": "user_id",
                "foreignField": "_id",
                "as": "author",
            }
        }
    )
    pipeline.append({"$unwind": {"path": "$author", "preserveNullAndEmptyArrays": True}})

    pipeline.append(
        {
            "$project": {
                "title": 1,
                "content": 1,
                "tags": 1,
                "status": 1,
                "created_at": 1,
                "updated_at": 1,
                "user_id": 1,
                "author.username": 1,
                "author.display_name": 1,
                "author.email": 1,
            }
        }
    )

    sort_field = data.get("sort_field", "created_at")
    sort_direction = -1 if data.get("sort_direction", "desc") == "desc" else 1
    pipeline.append({"$sort": {sort_field: sort_direction}})

    limit = min(int(data.get("limit", 20)), 100)
    pipeline.append({"$limit": limit})

    results = list(documents_collection.aggregate(pipeline))
    for item in results:
        item["_id"] = str(item["_id"])
        if "user_id" in item and isinstance(item["user_id"], ObjectId):
            item["user_id"] = str(item["user_id"])
        if "created_at" in item and isinstance(item["created_at"], datetime):
            item["created_at"] = item["created_at"].isoformat()
        if "updated_at" in item and isinstance(item["updated_at"], datetime):
            item["updated_at"] = item["updated_at"].isoformat()
    return jsonify({"count": len(results), "results": results}), 200


